import{_ as a,o as n,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"52. Cashing Out Of Annual Leave","description":"","frontmatter":{"title":"52. Cashing Out Of Annual Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","annual-leave","wages","superannuation"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/52-cashing-out-of-annual-leave.md","filePath":"ebas/biomedical-engineers/leave/52-cashing-out-of-annual-leave.md"}'),l={name:"ebas/biomedical-engineers/leave/52-cashing-out-of-annual-leave.md"};function s(i,e,u,r,p,c){return n(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_52-cashing-out-of-annual-leave" tabindex="-1">52. Cashing Out Of Annual Leave <a class="header-anchor" href="#_52-cashing-out-of-annual-leave" aria-label="Permalink to &quot;52. Cashing Out Of Annual Leave&quot;">​</a></h1><p><strong>52.1</strong> Subject to subclause 52.2 below, where an Employee has accrued annual leave in excess of eight (8) weeks then by mutual written agreement between the Employee and the Employer, the Employee may cash out some of the annual leave (and annual leave loading as applicable) due to the Employee as a one off cash payment. Superannuation contributions will be paid by the Employer in respect of the period of annual leave to be paid out.</p><p><strong>52.2</strong> Cashing out of accrued annual leave in accordance with this clause is subject to:</p><p><strong>(a)</strong> Paid annual leave must not be cashed out if the cashing out would result in the Employee’s remaining accrued entitlement to paid annual leave being less than 4 weeks; and</p><p><strong>(b)</strong> Each cashing out of a particular amount of paid annual leave must be by separate agreement in writing between the Employer and Employee; and</p><p><strong>(c)</strong> The Employee must be paid at least the full amount that would have been payable to the Employee had the Employee taken the leave that the Employee has foregone.</p><p><strong>52.3</strong> An Employee&#39;s accrued annual leave entitlement will be reduced by the amount of annual leave paid out.</p><p>Plain language terms: holidays, vacation.</p>',8)])])}const m=a(l,[["render",s]]);export{d as __pageData,m as default};
